import{_ as t,o,c as a,a2 as r}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Browser Timings","description":"","frontmatter":{},"headers":[],"relativePath":"ru/configuration/browser-timings.md","filePath":"ru/configuration/browser-timings.md"}'),i={name:"ru/configuration/browser-timings.md"};function n(c,e,s,d,m,l){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="browser-timings" tabindex="-1"><i class="ph ph-clock-countdown"></i> Browser Timings <a class="header-anchor" href="#browser-timings" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-clock-countdown&quot;&gt;&lt;/i&gt; Browser Timings&quot;">​</a></h1><p>Эта страница описывает технические ограничения архитектуры WebGL, связанные с параметром <code>Application.targetFrameRate</code>.</p><p>При компиляции Unity-проекта под WebGL, параметр <code>Application.targetFrameRate</code> меняет не просто внутренний лимит кадров движка, а <strong>базовый API браузера</strong>, через который работает игровой цикл (Main Loop).</p><h2 id="без-ограничении-requestanimationframe" tabindex="-1">Без ограничений (requestAnimationFrame) <a class="header-anchor" href="#без-ограничении-requestanimationframe" aria-label="Permalink to &quot;Без ограничений (requestAnimationFrame)&quot;">​</a></h2><p>Если вы снимаете лимит кадров (устанавливаете <code>Application.targetFrameRate</code> в <code>-1</code> или <code>0</code>, в зависимости от версии Unity), сборщик Emscripten привязывает главный цикл Unity напрямую к браузерному API <code>window.requestAnimationFrame</code>.</p><ul><li><strong>Плюсы:</strong> Это нативный, самый плавный и правильный способ рендеринга в вебе. Браузер сам синхронизирует вызовы с частотой обновления монитора игрока (VSync).</li><li><strong>Профилирование:</strong> Метрика <code>cpuMainThreadFrameTime</code> (которую читает WebAP) отражает <strong>реальное</strong> время, затраченное процессором на расчеты физики и скриптов.</li></ul><h2 id="искусственныи-лимит-settimeout" tabindex="-1">Искусственный лимит (setTimeout) <a class="header-anchor" href="#искусственныи-лимит-settimeout" aria-label="Permalink to &quot;Искусственный лимит (setTimeout)&quot;">​</a></h2><p>Если вы жестко фиксируете частоту кадров (например, <code>Application.targetFrameRate = 30</code>), Emscripten вынужден отказаться от <code>requestAnimationFrame</code>. Вместо этого он использует API <code>setTimeout()</code> или сложную комбинацию внутренних таймеров для искусственного замедления цикла.</p><div class="warning custom-block"><p class="custom-block-title">Искажение метрик CPU (The Emscripten Trap)</p><p>Искусственный таймер создает серьезное расхождение при измерении времени CPU. Процессор может просчитать всю игровую логику за 5 мс и уйти в простой, но корутина <code>WaitForEndOfFrame</code> не возобновится, пока не истечет таймер <code>setTimeout</code>.</p><p><strong>В результате:</strong> <code>FrameTimingManager</code> запишет это время ожидания в тайминг CPU. Профайлер (и трекер WebAP) будет считать, что у вас <em>CPU Bottleneck</em>, хотя на самом деле процессор функционально свободен, а кадр просто ждет таймера браузера.</p></div><h2 id="как-правильно-настроить" tabindex="-1">Как правильно настроить? <a class="header-anchor" href="#как-правильно-настроить" aria-label="Permalink to &quot;Как правильно настроить?&quot;">​</a></h2><p>Для идеальной работы Web Adaptive Performance в браузере:</p><ol><li><strong>Не используйте <code>Application.targetFrameRate</code></strong>. Оставьте его равным <code>-1</code> (снято).</li><li>Укажите желаемый FPS в настройках самого плагина (<code>Target Min FPS = 60</code>). WebAP будет использовать это значение не как хард-лимит, а как якорь для принятия решений о качестве графики.</li></ol>',12)])])}const g=t(i,[["render",n]]);export{u as __pageData,g as default};
